text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 스모크 테스트 통과 조건부로 금요일 15:00 KST로 정한다.",
        "condition": "스모크 테스트가 통과해야 함",
        "certainty": "confirmed"
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다.",
        "condition": "계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토함",
        "certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 변경한다.",
        "proposer": "Hara",
        "outcome": "rejected"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "proposer": "Seoyeon",
        "status": "internal stretch goal only",
        "reason": "Doyun이 스모크 테스트 통과가 먼저 필요하다고 반대함"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계는 목요일까지 가능하면 검토해야 한다는 의견이 있었으나 담당자는 정해지지 않았다.",
        "status": "not assigned"
      },
      {
        "item": "내부 수요일 stretch goal을 릴리스 노트에 언급할지 여부는 결정되지 않았다.",
        "status": "open"
      },
      {
        "item": "최종 릴리스 승인 권한자는 확인되지 않았다.",
        "status": "open"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 릴리스를 지연시킬 수 있다.",
        "certainty": "confirmed"
      },
      {
        "risk": "README 설치 단계가 오래되었으면 릴리스 노트가 사용자를 오도할 수 있다.",
        "certainty": "confirmed"
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "confirmed_no_exact_deadline",
      "source_certainty": "explicit"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 목요일까지 가능하면 검토한다.",
      "due": "목요일 if possible",
      "status": "suggested_unassigned",
      "source_certainty": "explicit_owner_missing"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 금요일 10:00 KST 스모크 테스트 결과 공유 여부",
      "Doyun의 금요일 12:00 KST action_items.md 실패 triage note 작성 여부",
      "스모크 테스트 통과 여부에 따른 금요일 15:00 KST 공개 릴리스 진행 가능성",
      "Hara의 generated tarball path 확인 결과",
      "README 설치 단계 검토 담당자 지정 여부",
      "최종 릴리스 승인 권한자 확인",
      "릴리스 노트에 내부 수요일 stretch goal을 언급할지 여부"
    ],
    "what_not_to_invent": [
      "고객명",
      "외부 파트너",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "정해지지 않은 owner",
      "정해지지 않은 deadline"
    ]
  },
  "non_invention_rules": {
    "customer": "고객 또는 외부 파트너는 언급되지 않았으므로 생성하지 않는다.",
    "budget": "예산 정보는 언급되지 않았으므로 생성하지 않는다.",
    "security": "보안 사고는 언급되지 않았으므로 생성하지 않는다.",
    "outage": "프로덕션 장애는 언급되지 않았으므로 생성하지 않는다.",
    "legal": "법무 승인 요구사항은 언급되지 않았으므로 생성하지 않는다.",
    "owners": "명시되지 않은 담당자는 null 또는 unassigned로 둔다.",
    "deadlines": "명시되지 않은 마감은 null 또는 no exact deadline으로 둔다.",
    "release_condition": "금요일 15:00 KST 공개 릴리스는 스모크 테스트 통과 조건부로만 기록한다."
  }
}
